    76→static inline void ConvertLabToXYZ(const double L,const double a,const double b,
    77→  double *X,double *Y,double *Z)
    78→{
    79→  double
    80→    x,
    81→    y,
    82→    z;
    83→
    84→  assert(X != (double *) NULL);
    85→  assert(Y != (double *) NULL);
    86→  assert(Z != (double *) NULL);
