    88→  x=y+a/500.0;
    89→  z=y-b/200.0;
    90→  if ((x*x*x) > CIEEpsilon)
    91→    x=(x*x*x);
    92→  else
    93→    x=(116.0*x-16.0)/CIEK;
    94→  if ((y*y*y) > CIEEpsilon)
    95→    y=(y*y*y);
    96→  else
    97→    y=L/CIEK;
    98→  if ((z*z*z) > CIEEpsilon)
    99→    z=(z*z*z);
   100→  else
   101→    z=(116.0*z-16.0)/CIEK;
   102→  *X=D65X*x;
   103→  *Y=D65Y*y;
   104→  *Z=D65Z*z;
   105→}
